class Solution {
    public int longestSubsequence(String s, int k) {
        int n = s.length();
        int[] dp = new int[k + 1];

        for (int i = 0; i <= n; i++) {
            for (int j = 0; j <= k; j++) {
                if (s.charAt(i - 1) == '0') {
                    dp[j] = Math.max(dp[j], dp[j - s.charAt(i - 1)];
                } else {
                    dp[j] = Math.max(dp[j], dp[j - 1]);
                }
            }
        }

        return dp[k];
    }
}
